func openHat(ctx context.Context, c *cli.Command) error {
	width := getTermWidth()

	contentWidth := utf8.RuneCountInString(soldOutLines[0])
	pad := (width - contentWidth) / 2
	if pad < 0 {
		pad = 0
	}
	prefix := strings.Repeat(" ", pad)

	fmt.Println()
	for _, line := range soldOutLines {
		fmt.Println(prefix + mercuryBlue.Render(line))
	}

	fmt.Println()
	for _, msg := range []string{
		"Dear Mercury CLI user,",
		"Your dedication to modern banking has not gone unnoticed.",
		"Unfortunately, the hat is sold out.",
	} {
		mw := lipgloss.Width(msg)
		mpad := (width - mw) / 2
		if mpad < 0 {
			mpad = 0
		}
		fmt.Println(strings.Repeat(" ", mpad) + soldOutDim.Render(msg))
	}
	fmt.Println()
	return nil
}
